import json

# Load packages data and find latest release per package
packages_file = locals()['var_functions.query_db:18']
with open(packages_file, 'r') as f:
    all_packages = json.load(f)

# Group by package name and find the latest release (max ordinal)
latest_releases = {}
for pkg in all_packages:
    name = pkg['Name']
    ordinal = int(pkg['Ordinal'])

    if name not in latest_releases or ordinal > latest_releases[name]['Ordinal']:
        latest_releases[name] = {
            'Name': name,
            'Version': pkg['Version'],
            'Ordinal': ordinal
        }

# Convert to list
latest_packages = list(latest_releases.values())

print('__RESULT__:')
print(json.dumps({
    'total_packages': len(latest_packages),
    'sample': latest_packages[:5]
}, default=str))

